module RefModule (
    input clk,
    input reset,
    input t,
    output q );reg unused_q_reg;

    always @(posedge clk) begin
        if (reset)
            unused_q_reg <= 1'b0;
        else if (t)
            unused_q_reg <= ~unused_q_reg;
    end

    assign q = unused_q_reg;

endmodule
